package com.example.bankapp;

import android.os.Bundle;
import androidx.appcompat.app.AppCompatActivity;
import android.widget.TextView;

public class MainActivity extends AppCompatActivity {

    private TextView balanceTextView;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        balanceTextView = findViewById(R.id.balanceTextView);
        updateBalance(1000.00); // Initial balance for demonstration

        // Simulate a transaction
        processTransaction(500.00, "Withdrawal");
    }

    private void updateBalance(double balance) {
        balanceTextView.setText(String.format("Current Balance: $%.2f", balance));
    }

    private void processTransaction(double amount, String type) {
        double currentBalance = Double.parseDouble(balanceTextView.getText().toString().replace("Current Balance: $", ""));
        if (type.equals("Withdrawal")) {
            if (currentBalance >= amount) {
                updateBalance(currentBalance - amount);
            } else {
                // Handle insufficient funds
            }
        } else if (type.equals("Deposit")) {
            updateBalance(currentBalance + amount);
        }
    }
}